def caesar_cipher(text: str, shift: int) -> str:
    if not isinstance(text, str) or not isinstance(shift, int) or isinstance(shift, bool):
        return ""
    result = []
    for ch in text:
        if ch.isalpha():
            base = ord('A') if ch.isupper() else ord('a')
            shifted = chr((ord(ch) - base + shift) % 26 + base)
            result.append(shifted)
        else:
            result.append(ch)
    return "".join(result)

def is_palindrome(value) -> bool:
    if isinstance(value, bool):
        return False
    if not isinstance(value, (int, str)):
        return False
    if isinstance(value, int):
        if value < 0:
            return False
        value = str(value)
    if value == "":
        return False
    value = value.lower()
    return value == value[::-1]

def sum_numbers(values) -> float | None:
    import math
    if not isinstance(values, list):
        return None
    total = 0.0
    for item in values:
        if isinstance(item, bool):
            return None
        if not isinstance(item, (int, float)):
            return None
        if isinstance(item, float) and (math.isinf(item) or math.isnan(item)):
            return None
        total += item
    return float(total)

def subtract_numbers(values) -> float | None:
    import math
    if not isinstance(values, list):
        return None
    if not values:
        return 0.0
    for item in values:
        if isinstance(item, bool):
            return None
        if not isinstance(item, (int, float)):
            return None
        if isinstance(item, float) and (math.isinf(item) or math.isnan(item)):
            return None
    result = float(values[0])
    for number in values[1:]:
        result -= number
    return float(result)
